class ImageMosaic {
	constructor() {
		this.image = null;
		this.imageUrl =
			"https://images.unsplash.com/photo-1681759744587-7b62d82f8d70?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0";
		this.tileCount = 25;
		this.defaultImageLoaded = !1;
		this.controlsVisible = !1;
		this.currentAction = "pop";
		this.initElements();
		this.initEventListeners();
		this.loadDefaultImage();
		console.log("&Toc on codepen - https://codepen.io/ol-ivier");
	}
	initElements() {
		this.imageInput = document.getElementById("imageInput");
		this.tileSlider = document.getElementById("tileSlider");
		this.mosaic = document.getElementById("mosaic");
		this.errorMessage = document.getElementById("errorMessage");
		this.resetBtn = document.getElementById("resetBtn");
		this.toggleBtn = document.getElementById("toggleControls");
		this.floatingControls = document.getElementById("floatingControls");
		this.container = document.getElementById("container");
		this.resetInteractionsBtn = document.getElementById("resetInteractionsBtn");
	}
	initEventListeners() {
		this.imageInput.addEventListener("change", (e) => this.handleImageUpload(e));
		this.tileSlider.addEventListener("input", (e) => this.handleTileChange(e));
		this.resetBtn.addEventListener("click", () => this.resetToDefault());
		this.toggleBtn.addEventListener("click", () => this.toggleControls());
		this.resetInteractionsBtn.addEventListener("click", () =>
			this.resetAllTiles()
		);
		document.querySelectorAll(".interaction-btn").forEach((btn) => {
			btn.addEventListener("click", (e) => {
				document
					.querySelectorAll(".interaction-btn")
					.forEach((b) => b.classList.remove("active"));
				e.target.classList.add("active");
				this.currentAction = e.target.dataset.action;
			});
		});
		window.addEventListener("resize", () => {
			if (this.defaultImageLoaded) this.createMosaic();
		});
	}
	toggleControls() {
		this.controlsVisible = !this.controlsVisible;
		this.floatingControls.classList.toggle("hidden", !this.controlsVisible);
		this.toggleBtn.classList.toggle("hidden", !this.controlsVisible);
	}
	loadDefaultImage() {
		this.image = new Image();
		this.image.crossOrigin = "anonymous";
		this.image.onload = () => {
			this.defaultImageLoaded = !0;
			this.createMosaic();
		};
		this.image.onerror = () => {
			this.useFallbackImage();
		};
		this.image.src = this.imageUrl;
	}
	useFallbackImage() {
		this.imageUrl =
			"data:image/svg+xml;base64,";
		this.image = new Image();
		this.image.onload = () => {
			this.defaultImageLoaded = !0;
			this.createMosaic();
		};
		this.image.src = this.imageUrl;
	}
	resetToDefault() {
		this.imageUrl =
			"https://images.unsplash.com/photo-1681759744587-7b62d82f8d70?w=500&auto=format&w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0";
		this.tileSlider.value = 25;
		this.tileCount = 25;
		this.loadDefaultImage();
		document.querySelector("#infos").style.display = "";
	}
	handleImageUpload(event) {
		const file = event.target.files[0];
		document.querySelector("#infos").style.display = "none";
		if (!file) return;
		if (!file.type.startsWith("image/")) {
			this.showError("Le fichier doit être une image");
			return;
		}
		const reader = new FileReader();
		reader.onload = (e) => {
			this.imageUrl = e.target.result;
			this.image = new Image();
			this.image.onload = () => {
				this.defaultImageLoaded = !0;
				this.createMosaic();
				this.hideError();
			};
			this.image.onerror = () => {
				this.showError("Erreur lors du chargement de l'image");
			};
			this.image.src = this.imageUrl;
		};
		reader.onerror = () => {
			this.showError("Erreur lors de la lecture du fichier");
		};
		reader.readAsDataURL(file);
	}
	handleTileChange(event) {
		const rawValue = parseInt(event.target.value);
		const safeValue = Math.max(4, Math.min(100, rawValue));
		const tilesPerSide = Math.round(Math.sqrt(safeValue));
		this.tileCount = tilesPerSide * tilesPerSide;
		this.tileSlider.value = this.tileCount;
		if (this.defaultImageLoaded) {
			this.createMosaic();
		}
	}
	handleTileClick(tile, row, col) {
		switch (this.currentAction) {
			case "pop":
				this.actionPop(tile);
				break;
			case "zoom":
				this.actionZoom(tile);
				break;
			case "rotate":
				this.actionRotate(tile);
				break;
			case "swap":
				this.actionSwap(tile, row, col);
				break;
			case "color":
				this.actionColor(tile);
				break;
		}
	}
	actionPop(tile) {
		tile.classList.add("pop");
		setTimeout(() => tile.classList.remove("pop"), 300);
	}
	actionZoom(tile) {
		tile.style.zIndex = "1000";
		tile.style.transform = "scale(2)";
		tile.style.transition = "all 0.3s ease";
		setTimeout(() => {
			tile.style.zIndex = "1";
			tile.style.transform = "scale(1)";
		}, 1000);
	}
	actionRotate(tile) {
		tile.classList.add("rotate");
		setTimeout(() => tile.classList.remove("rotate"), 500);
	}
	actionSwap(tile, row, col) {
		const tiles = Array.from(this.mosaic.children);
		const randomIndex = Math.floor(Math.random() * tiles.length);
		const randomTile = tiles[randomIndex];
		if (randomTile && randomTile !== tile) {
			const tempBg = tile.style.backgroundImage;
			const tempPos = tile.style.backgroundPosition;
			const tempSize = tile.style.backgroundSize;
			tile.style.backgroundImage = randomTile.style.backgroundImage;
			tile.style.backgroundPosition = randomTile.style.backgroundPosition;
			tile.style.backgroundSize = randomTile.style.backgroundSize;
			randomTile.style.backgroundImage = tempBg;
			randomTile.style.backgroundPosition = tempPos;
			randomTile.style.backgroundSize = tempSize;
			tile.classList.add("pop");
			randomTile.classList.add("pop");
			setTimeout(() => {
				tile.classList.remove("pop");
				randomTile.classList.remove("pop");
			}, 300);
		}
	}
	actionColor(tile) {
		const hue = Math.random() * 360;
		tile.style.filter = `hue-rotate(${hue}deg)`;
		tile.classList.add("pop");
		setTimeout(() => tile.classList.remove("pop"), 300);
	}
	resetAllTiles() {
		const tiles = Array.from(this.mosaic.children);
		tiles.forEach((tile) => {
			tile.style.transform = "";
			tile.style.zIndex = "";
			tile.style.opacity = "";
			tile.style.filter = "";
			tile.classList.remove("pop", "rotate");
			if (this.originalBackgrounds && this.originalBackgrounds.get(tile)) {
				const orig = this.originalBackgrounds.get(tile);
				tile.style.backgroundImage = orig.image;
				tile.style.backgroundPosition = orig.position;
				tile.style.backgroundSize = orig.size;
			}
		});
	}
	createMosaic() {
		if (!this.defaultImageLoaded || !this.image) return;
		const tilesPerSide = Math.max(
			2,
			Math.min(10, Math.round(Math.sqrt(this.tileCount)))
		);
		this.mosaic.style.gridTemplateColumns = `repeat(${tilesPerSide}, 1fr)`;
		this.mosaic.style.gridTemplateRows = `repeat(${tilesPerSide}, 1fr)`;
		this.mosaic.innerHTML = "";
		this.originalBackgrounds = new Map();
		const imgWidth = this.image.width;
		const imgHeight = this.image.height;
		const size = Math.min(imgWidth, imgHeight);
		const offsetX = (imgWidth - size) / 2;
		const offsetY = (imgHeight - size) / 2;
		const canvas = document.createElement("canvas");
		const ctx = canvas.getContext("2d");
		canvas.width = size;
		canvas.height = size;
		ctx.drawImage(this.image, offsetX, offsetY, size, size, 0, 0, size, size);
		const croppedImageUrl = canvas.toDataURL("image/jpeg", 0.9);
		for (let row = 0; row < tilesPerSide; row++) {
			for (let col = 0; col < tilesPerSide; col++) {
				const tile = document.createElement("div");
				tile.className = "tile";
				const tileSize = size / tilesPerSide;
				const tileX = col * tileSize;
				const tileY = row * tileSize;
				const bgPosX = (tileX / (size - tileSize)) * 100;
				const bgPosY = (tileY / (size - tileSize)) * 100;
				const bgSize = (size / tileSize) * 100;
				tile.style.backgroundImage = `url('${croppedImageUrl}')`;
				tile.style.backgroundPosition = `${bgPosX}% ${bgPosY}%`;
				tile.style.backgroundSize = `${bgSize}% ${bgSize}%`;
				tile.style.backgroundRepeat = "no-repeat";
				this.originalBackgrounds.set(tile, {
					image: `url('${croppedImageUrl}')`,
					position: `${bgPosX}% ${bgPosY}%`,
					size: `${bgSize}% ${bgSize}%`
				});
				tile.addEventListener("click", (e) => {
					e.stopPropagation();
					this.handleTileClick(tile, row, col);
				});
				this.mosaic.appendChild(tile);
			}
		}
	}
	showError(message) {
		this.errorMessage.textContent = message;
		this.errorMessage.style.display = "block";
		setTimeout(() => this.hideError(), 3000);
	}
	hideError() {
		this.errorMessage.style.display = "none";
	}
}
document.addEventListener("DOMContentLoaded", () => {
	new ImageMosaic();
});

style.css:
* {
	margin: 0;
	padding: 0;
	box-sizing: border-box;
}

body {
	font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
	overflow: hidden;
	height: 100vh;
	width: 100vw;
	position: relative;
	background: #000;
}

.container {
	width: 100vw;
	height: 100vh;
	display: flex;
	align-items: center;
	justify-content: center;
}

.mosaic-container {
	background: #2c3e50;
	width: 100%;
	height: 100%;
	display: flex;
	justify-content: center;
	align-items: center;
	position: relative;
}

#mosaic {
	display: grid;
	background-color: #34495e;
	overflow: hidden;
	box-shadow: 0 10px 30px rgb(0 0 0 / 0.3);
	width: min(95vh, 95vw);
	height: min(95vh, 95vw);
	aspect-ratio: 1 / 1;
	position: relative;
}

.tile {
	background-size: cover;
	background-repeat: no-repeat;
	border: 1px solid rgb(255 255 255 / 0.2);
	transition: all 0.3s ease;
	cursor: pointer;
	width: 100%;
	height: 100%;
	aspect-ratio: 1 / 1;
	position: relative;
	overflow: hidden;
}

.tile:hover {
	transform: scale(1.1);
	z-index: 10;
	box-shadow: 0 0 20px rgb(52 152 219 / 0.8);
	border: 2px solid #fff;
}

.tile.pop {
	animation: pop 0.3s ease;
}

@keyframes pop {
	0% {
		transform: scale(1);
	}

	50% {
		transform: scale(1.3);
		z-index: 100;
	}

	100% {
		transform: scale(1);
	}
}

.tile.rotate {
	animation: rotate 0.5s ease;
}

@keyframes rotate {
	0% {
		transform: rotate(0deg);
	}

	100% {
		transform: rotate(360deg);
	}
}

.toggle-controls-btn {
	position: fixed;
	top: 20px;
	right: 20px;
	width: 36px;
	height: 36px;
	border-radius: 50%;
	background: rgb(52 152 219 / 0.3);
	color: rgb(255 255 255 / 0.6);
	border: 1px solid rgb(255 255 255 / 0.1);
	cursor: pointer;
	font-size: 18px;
	display: flex;
	align-items: center;
	justify-content: center;
	z-index: 1002;
	transition: all 0.3s ease;
	backdrop-filter: blur(4px);
	padding: 0;
}

.toggle-controls-btn:hover {
	background: rgb(52 152 219 / 0.6);
	color: #fff;
}

.toggle-controls-btn.hidden {
	background: rgb(231 76 60 / 0.3);
}

.toggle-controls-btn svg {
	width: 20px;
	height: 20px;
	fill: #fff;
	position: absolute;
	transition: opacity 0.3s ease;
}

.toggle-controls-btn .eye-open {
	opacity: 1;
}

.toggle-controls-btn .eye-closed {
	opacity: 0;
}

.toggle-controls-btn.hidden .eye-open {
	opacity: 0;
}

.toggle-controls-btn.hidden .eye-closed {
	opacity: 1;
}

.floating-controls {
	position: fixed;
	top: 10px;
	right: 10px;
	width: 200px;
	background: rgb(30 30 30 / 0.7);
	backdrop-filter: blur(10px);
	border-radius: 12px;
	padding: 10px 16px;
	box-shadow: 0 5px 20px rgb(0 0 0 / 0.2);
	border: 1px solid rgb(255 255 255 / 0.08);
	z-index: 1000;
	transition: all 0.3s ease;
	color: rgb(255 255 255 / 0.7);
}

.floating-controls.hidden {
	transform: translateX(calc(100% + 20px)) translateY(-50%);
	opacity: 0;
	pointer-events: none;
}

.upload-section {
	margin-bottom: 20px;
}

.upload-btn {
	background: rgb(52 152 219 / 0.2);
	color: rgb(255 255 255 / 0.8);
	padding: 6px 12px;
	border-radius: 30px;
	cursor: pointer;
	font-weight: 400;
	font-size: 0.9em;
	transition: all 0.3s;
	border: 1px solid rgb(255 255 255 / 0.1);
	display: flex;
	align-items: center;
	justify-content: center;
	gap: 6px;
	width: 75%;
	backdrop-filter: blur(4px);
}

.upload-btn:hover {
	background: rgb(52 152 219 / 0.4);
	color: #fff;
}

.upload-btn input {
	display: none;
}

.slider-wrapper {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 8px;
	margin-bottom: 12px;
}

.slider-wrapper input[type="range"] {
	width: 100%;
	height: 38px;
	margin: 2px 0 10px 0;
	accent-color: #3498db;
	height: 4px;
	opacity: 0.6;
	transition: opacity 0.3s;
	height: 10px;
	/*! padding-bottom: 10px; */
}

.slider-wrapper input[type="range"]:hover {
	opacity: 1;
}

.reset-btn {
	background: rgb(149 165 166 / 0.2);
	color: rgb(255 255 255 / 0.7);
	border: 1px solid rgb(255 255 255 / 0.1);
	padding: 6px 10px;
	border-radius: 30px;
	cursor: pointer;
	font-weight: 400;
	transition: all 0.3s;
	font-size: 0.8em;
	width: 100%;
	backdrop-filter: blur(4px);
	text-align: center;
}

.reset-btn:hover {
	background: rgb(149 165 166 / 0.4);
	color: #fff;
}

.interaction-selector {
	margin-bottom: 12px;
}

.interaction-title {
	font-size: 0.8em;
	color: rgb(255 255 255 / 0.5);
	margin-bottom: 6px;
	text-align: center;
	letter-spacing: 0.5px;
}

.interaction-buttons {
	display: flex;
	flex-wrap: wrap;
	gap: 6px;
	justify-content: center;
}

.interaction-btn {
	background: rgb(255 255 255 / 0.1);
	color: rgb(255 255 255 / 0.6);
	border: 1px solid rgb(255 255 255 / 0.1);
	padding: 6px 10px;
	border-radius: 20px;
	cursor: pointer;
	font-size: 0.75em;
	transition: all 0.2s;
	flex: 1 0 auto;
	min-width: 70px;
}

.interaction-btn:hover {
	background: rgb(255 255 255 / 0.2);
	color: #fff;
}

.interaction-btn.active {
	background: #3498db;
	color: #fff;
	border-color: #3498db;
}

.error-message {
	color: #e74c3c;
	text-align: center;
	margin-top: 10px;
	padding: 10px;
	border-radius: 5px;
	background: #fadbd8;
	display: none;
	position: fixed;
	bottom: 20px;
	left: 50%;
	transform: translateX(-50%);
	z-index: 1001;
}

.infos {
	position: fixed;
	bottom: 20px;
	right: 20px;
	color: #fff;
	background: rgb(0 0 0 / 0.5);
	padding: 10px;
	border-radius: 5px;
	font-size: 14px;
}

.copy {
	position: fixed;
	top: 20px;
	left: 20px;
	color: #000;
	background: rgb(255 255 255 / 0.9);
	padding: 10px;
	border-radius: 5px;
	font-size: 12px;
}

a {
	text-decoration: none;
	color: #51e7e0;
}

a:hover {
	color: #fff;
	transition: all 0.6s ease;
}

@media (max-width: 768px) {
	.floating-controls {
		width: 95%;
	}

	.floating-controls.hidden {
		transform: translateX(50%) translateY(calc(100% + 20px));
	}

	#mosaic {
		width: min(90vw, 90vh);
		height: min(90vw, 90vh);
	}
}
